/* 아이디 찾기 */
select 
	user_id
from tb_user
where del_yn = 'N'
and psn_name = #{psnName}
and psn_mobile = #{psnMobile}

/* 아이디 찾기 */
select 
	user_pw
from tb_user
where del_yn = 'N'
and user_id = #{userId}
and psn_name = #{psnName}
and psn_mobile = #{psnMobile}

/* 아이디 중복 조회 */
select 
	user_idx, user_id
from tb_user
where del_yn = 'N'
and user_id = #{userId }

