/* 사용자 수정 */ update tb_user set
user_pw = sha2(#{userPw }, 256), /* 패스워드 */
psn_mobile = #{psnMobile }, /* 담당자휴대폰번호 */ psn_email = #{psnEmail }, /* 담당자이메일주소 */ mod_uid = #{modUid }, mod_date = now() where 1=1 and user_idx = #{userIdx }
